+import { $internal } from '../common';
+import type { Trait, TraitRecord } from '../trait/types';
+
+export const $aspect = Symbol.for('koota.aspect');
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+} & ((params?: Partial<AspectRecord<T>>) => [Aspect<T>, Partial<AspectRecord<T>>]);
+
+export type AspectRecord<T extends readonly Trait[]> = UnionToIntersection<
+    TraitRecord<T[number]>
+>;
+
+type UnionToIntersection<T> = (T extends any ? (value: T) => void : never) extends (
+    value: infer I
+) => void
+    ? I
+    : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect)?.[$aspect];
+}
+
+export function createAspect<T extends readonly [Trait | Aspect, Trait | Aspect, ...(Trait | Aspect)[]]>(
+    ...inputs: T
+): Aspect<FlattenAspects<T>> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (trait[$internal].relation) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        if (typeof trait.schema === 'function') continue;
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: Aspect constituents cannot share the field "${field}".`);
+            }
+            fields.add(field);
+            schema[field] = trait.schema[field];
+        }
+    }
+
+    const id = aspectId++;
+    const aspect = Object.assign((params: Partial<AspectRecord<FlattenAspects<T>>> = {}) => [aspect, params], {
+        [$aspect]: true as const,
+        id,
+        traits: Object.freeze(traits),
+        schema: Object.freeze(schema),
+    }) as Aspect<FlattenAspects<T>>;
+
+    return aspect;
+}
+
+type FlattenOne<T> = T extends Aspect<infer Traits> ? Traits[number] : T extends Trait ? T : never;
+type FlattenAspects<T extends readonly unknown[]> = { [K in keyof T]: FlattenOne<T[K]> };
