+    ) as (Trait | import('../aspect/aspect').Aspect)[];
+    const results = Object.assign(entities, {
+        readEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                callback(readable.map((param) => getTrait(world, entity, param)), entity, i);
+            }
+            return results;
+        },
+        updateEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readable.map((param) => getTrait(world, entity, param));
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                for (let j = 0; j < readable.length; j++) setTrait(world, entity, readable[j], state[j]);
+            }
+            return results;
+        },
